-- ----------------------------
-- Table structure for myapp01_commenthot4
-- ----------------------------
DROP TABLE IF EXISTS `myapp01_commenthot4`;
CREATE TABLE `myapp01_commenthot4`  (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `nickname` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `region` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL,
  `comment_date` datetime(6) NOT NULL,
  `content` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `like_count` int NOT NULL,
  `created_at` datetime(6) NOT NULL,
  `video_id` bigint NULL DEFAULT NULL,
  `hot_board_id` bigint NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `myapp01_comment_3_video_id_a9b281a4_fk_myapp01_video_id`(`video_id` ASC) USING BTREE,
  INDEX `myapp01_commenthot4_hot_board_id_99805a55_fk_myapp01_hotboard_id`(`hot_board_id` ASC) USING BTREE,
  CONSTRAINT `myapp01_comment_3_video_id_a9b281a4_fk_myapp01_video_id` FOREIGN KEY (`video_id`) REFERENCES `myapp01_video` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT,
  CONSTRAINT `myapp01_commenthot4_hot_board_id_99805a55_fk_myapp01_hotboard_id` FOREIGN KEY (`hot_board_id`) REFERENCES `myapp01_hotboard` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 2044 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci;

