INSERT INTO `myapp01_commenthot4` (`id`, `nickname`, `region`, `comment_date`, `content`, `like_count`, `created_at`, `video_id`, `hot_board_id`) VALUES (1647, '小雨妈妈', '湖南', '2025-03-30 18:13:51.000000', '伊利和蒙牛消耗了国人太多的信任，但凡产品质量正常点都能垄断了', 263, '2025-03-30 15:54:23.794662', NULL, 1422), (1648, '狼被围歼', '吉林', '2025-03-30 23:24:06.000000', '[微笑]都说蒙牛伊利差，看着家里两箱蒙牛轻轻的碎了', 1, '2025-03-30 15:54:23.819267', NULL, 1422), (1649, '小夏小夏', '辽宁', '2025-03-30 18:38:43.000000', '有人说：蒙牛、伊利不要去碰，是真的吗？', 43, '2025-03-30 15:54:23.836221', NULL, 1422), (1650, '蒲公英小说', '河南', '2025-03-30 22:38:55.000000', '所以现在牛奶喝什么牌子好？', 6, '2025-03-30 15:54:23.852760', NULL, 1422), (1651, '脚踏七彩祥云', '江苏', '2025-03-30 23:48:42.000000', '一般老家附近都有奶牛厂，打听打听订个奶，比这些乱七八糟的牌子好多了，到城里反而不好找，偶尔去趟sam之类的囤一点喝喝，过年亲戚送的什么光明，蒙牛之类的都给我媳妇用来做咖啡了，扔了多可惜', 0, '2025-03-30 15:54:23.867328', NULL, 1422), (1652, '妮妈童装', '广东', '2025-03-30 23:53:01.000000', '弱问一下，蒙牛纯牛奶出啥事了吗？', 1, '2025-03-30 15:54:24.324827', NULL, 1422), (1653, '夏日冰冰茶', '湖南', '2025-03-30 23:02:42.000000', '以前的奶粉泡着真的浓甜 现在的寡淡[捂脸][捂脸]', 1, '2025-03-30 15:54:24.347291', NULL, 1422), (1654, '雨蝶', '江苏', '2025-03-30 18:47:55.000000', '有人说：蒙牛、伊利不要去碰，是真的吗？', 32, '2025-03-30 15:54:24.368462', NULL, 1422), (1655, '昭昭麻麻', '浙江', '2025-03-30 19:03:29.000000', '所以现在牛奶喝什么牌子？[暗中观察]', 14, '2025-03-30 15:54:24.387335', NULL, 1422), (1656, '千里江山', '湖北', '2025-03-30 23:17:09.000000', '这两个牌子,怎么还在，好没有倒闭。', 2, '2025-03-30 15:54:24.400599', NULL, 1422), (1657, '征 服', '浙江', '2025-03-30 20:25:49.000000', '国内牛奶做到高标准是光明牛奶吗？', 5, '2025-03-30 15:54:24.415538', NULL, 1422), (1658, '赏颜君', '广东', '2025-03-30 22:43:22.000000', '不懂就问：评论区里说蒙牛伊利只要是这两个牌子，一定不碰，问题太多。是真的吗？求解…', 12, '2025-03-30 15:54:24.428279', NULL, 1422), (1659, '酷酷的小强强', '辽宁', '2025-03-30 23:20:37.000000', '不养牛哪来的牛奶加工呢？', 2, '2025-03-30 15:54:24.460631', NULL, 1422), (1660, '黄小姐', '湖南', '2025-03-30 23:28:21.000000', '有什么好牛奶🥛推荐', 1, '2025-03-30 15:54:24.474876', NULL, 1422), (1661, '-想去冰岛', '河北', '2025-03-30 22:51:07.000000', '君乐宝 我们河北自己的牌子', 1, '2