-- ----------------------------
-- Table structure for myapp01_hotboard
-- ----------------------------
DROP TABLE IF EXISTS `myapp01_hotboard`;
CREATE TABLE `myapp01_hotboard`  (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `rank` int NOT NULL,
  `keyword` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `hot_value` int NOT NULL,
  `created_at` datetime(6) NOT NULL,
  `hot_search_id` bigint NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  INDEX `myapp01_hotboard_hot_search_id_d2f9997b_fk_myapp01_hotsearch_id`(`hot_search_id` ASC) USING BTREE,
  CONSTRAINT `myapp01_hotboard_hot_search_id_d2f9997b_fk_myapp01_hotsearch_id` FOREIGN KEY (`hot_search_id`) REFERENCES `myapp01_hotsearch` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 1469 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci;

