DROP TABLE IF EXISTS `myapp01_video`;
CREATE TABLE `myapp01_video`  (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `caption` longtext CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `video_date` datetime(6) NOT NULL,
  `video_id` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `user_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `collect_count` int NOT NULL,
  `share_count` int NOT NULL,
  `popularity` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL,
  `created_at` datetime(6) NOT NULL,
  `hot_search_id` bigint NULL DEFAULT NULL,
  PRIMARY KEY (`id`) USING BTREE,
  UNIQUE INDEX `video_id`(`video_id` ASC) USING BTREE,
  INDEX `myapp01_video_hot_search_id_e0fb769e_fk_myapp01_hotsearch_id`(`hot_search_id` ASC) USING BTREE,
  CONSTRAINT `myapp01_video_hot_search_id_e0fb769e_fk_myapp01_hotsearch_id` FOREIGN KEY (`hot_search_id`) REFERENCES `myapp01_hotsearch` (`id`) ON DELETE RESTRICT ON UPDATE RESTRICT
) ENGINE = InnoDB AUTO_INCREMENT = 23 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci;

