INSERT INTO `myapp01_video` (`id`, `caption`, `video_date`, `video_id`, `user_name`, `collect_count`, `share_count`, `popularity`, `created_at`, `hot_search_id`) VALUES (18, '汤加附近发生7.3级地震', '2025-03-30 20:58:42.000000', '7487585332297239819', '中国新闻社', 402, 3175, '正常', '2025-03-30 14:51:26.175181', NULL), (19, '缅甸强震死亡人数升至1700人#快看热点', '2025-03-30 15:31:21.000000', '7487501210019253544', '新华社快看', 879, 1710, '正常', '2025-03-30 14:51:29.359329', NULL), (20, '#星火成炬 ｜ 心赴广西三月三 #2025中国网络媒体论坛', '2025-03-29 11:51:23.000000', '7487073428332154149', '央视网', 11637, 13601, '热门', '2025-03-30 14:51:32.316751', NULL), (21, '【蒙牛净利润暴跌97.8%】 近日，上任一周年的高飞交出执掌公司的首份财报。蒙牛乳业2024年营收886.75亿元，同比下降10.1%；股东应占利润仅为1.05亿元，与上年的48.09亿元相比暴跌97.8%。营收下滑主要受乳制品行业供需失衡、消费需求不及预期等挑战影响；利润下滑主要受子公司贝拉米商誉及无形资产减值、联营公司现代牧业亏损拖累。（荔枝视频）#蒙牛2024年净利润暴跌 #蒙牛净利润暴跌98', '2025-03-30 17:45:25.000000', '7487534679101394210', '北京日报', 521, 1324, '正常', '2025-03-30 14:51:35.682128', NULL), (22, '血战托列茨克：俄用燃烧弹大规模轰击乌阵地，乌军不顾一切向前冲 #俄乌战争 #俄乌冲突 #理性看世界 #零基础看懂全球 #硬核深度计划', '2025-03-08 00:30:07.000000', '7479104121048534311', '铁血战史1927', 1991, 544, '正常', '2025-03-30 14:51:38.444911', NULL);
COMMIT;

